// Solution
var validatePortMappings = function(mappings) {
  let mappingsArray = mappings.split(',');
  let portSet = new Set();
  for (let mapping of mappingsArray) {
    let [port, service] = mapping.split(':');
    if (portSet.has(port)) return false;
    portSet.add(port);
  }
  return true;
};

