from typing import Set
from collections import Iterable

class Solution:
  def validate_port_mappings(self, mappings: str) -> bool:
    port_set = set()
    for mapping in mappings.split(', '):
      port, service = mapping.split(':')
      if port in port_set:
        return False
      port_set.add(port)
    return True
